import{_ as e,o as a,c as n,a0 as t}from"./chunks/framework.AQcSKqPn.js";const u=JSON.parse('{"title":"Shingeki no Kyojin Season 3 Part 2 — MyAnimeList Entry","description":"","frontmatter":{"type":"source","title":"Shingeki no Kyojin Season 3 Part 2 — MyAnimeList Entry","tags":["anime","attack-on-titan","shingeki-no-kyojin","myanimelist"],"related":["shingeki-no-kyojin","eren-yeager","survey-corps","wall-maria","shiganshina-district"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","authors":[],"year":2019,"url":"https://myanimelist.net/anime/38524","venue":"MyAnimeList","sources":["anime/38524.md"],"date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"sources/5-anime--5-38524--hnv61b.md","filePath":"sources/5-anime--5-38524--hnv61b.md","lastUpdated":1783753234000}'),r={name:"sources/5-anime--5-38524--hnv61b.md"};function s(o,i,l,h,m,d){return a(),n("div",null,[...i[0]||(i[0]=[t('<h1 id="shingeki-no-kyojin-season-3-part-2-—-myanimelist-条目" tabindex="-1">Shingeki no Kyojin Season 3 Part 2 — MyAnimeList 条目 <a class="header-anchor" href="#shingeki-no-kyojin-season-3-part-2-—-myanimelist-条目" aria-label="Permalink to &quot;Shingeki no Kyojin Season 3 Part 2 — MyAnimeList 条目&quot;">​</a></h1><p>《Shingeki no Kyojin Season 3 Part 2》（进击的巨人 第三季 Part 2）是2019年播出的日本动画，改编自谏山创的同名漫画。该季在MyAnimeList上获得9.05的高评分，共10集，状态为&quot;Finished Airing&quot;，类型涵盖动作、剧情与悬疑。</p><h2 id="剧情概要" tabindex="-1">剧情概要 <a class="header-anchor" href="#剧情概要" aria-label="Permalink to &quot;剧情概要&quot;">​</a></h2><p>为了恢复人类日益渺茫的希望，<a href="/llm-wiki/entities/survey-corps-调查兵团">survey-corps</a>发起了一场夺回<a href="/llm-wiki/entities/wall-maria-玛利亚之墙">wall-maria</a>的任务，与无情的&quot;巨人&quot;（Titans）的战斗再次拉开帷幕。</p><p>回到曾经是故乡的破败<a href="/llm-wiki/entities/shiganshina-district-希干希纳区">shiganshina-district</a>，<a href="/llm-wiki/entities/eren-yeager-艾伦耶格尔">eren-yeager</a>和调查兵团发现镇上异常地没有巨人的踪影。即使在外门被堵住后，他们仍然奇怪地没有遇到任何抵抗。任务进展顺利，直到<a href="/llm-wiki/entities/armin-arlert-阿明阿诺德">armin-arlert</a>对敌人的缺席高度怀疑，发现了异常……</p><h2 id="关键信息" tabindex="-1">关键信息 <a class="header-anchor" href="#关键信息" aria-label="Permalink to &quot;关键信息&quot;">​</a></h2><ul><li><strong>评分</strong>: 9.05（MyAnimeList）</li><li><strong>集数</strong>: 10</li><li><strong>播出年份</strong>: 2019</li><li><strong>类型</strong>: 动作、剧情、悬疑</li><li><strong>状态</strong>: 已完结</li></ul><h2 id="叙事意义" tabindex="-1">叙事意义 <a class="header-anchor" href="#叙事意义" aria-label="Permalink to &quot;叙事意义&quot;">​</a></h2><p>本季是《进击的巨人》系列的关键转折点，夺回玛利亚之墙的行动不仅关乎人类的生存希望，更揭示了关于巨人起源和世界真相的深层谜团。敌人反常的缺席这一悬念，为后续剧情的重大反转埋下了伏笔。</p>',9)])])}const y=e(r,[["render",s]]);export{u as __pageData,y as default};
